<?php
namespace Ronu\LaravelFederatedAuth\Providers;
use Ronu\LaravelFederatedAuth\DTO\AuthContext; use Ronu\LaravelFederatedAuth\Support\ProviderConfig;
class KeycloakProviderAdapter extends GenericOidcProviderAdapter { public function name(): string { return 'keycloak'; } public function supports(string $provider): bool { $cfg=config("federated-auth.providers.$provider"); return is_array($cfg)&&($cfg['driver']??null)==='keycloak'; } public function redirectUrl(AuthContext $context): string { $this->derive($context->provider); return parent::redirectUrl($context); } public function userFromCallback(AuthContext $context): \Ronu\LaravelFederatedAuth\DTO\ExternalIdentity { $this->derive($context->provider); return parent::userFromCallback($context); } public function userFromToken(string $token,AuthContext $context): \Ronu\LaravelFederatedAuth\DTO\ExternalIdentity { $this->derive($context->provider); return parent::userFromToken($token,$context); } private function derive(string $provider): void { $cfg=ProviderConfig::get($provider); if(!empty($cfg['base_url'])&&!empty($cfg['realm'])){ $base=rtrim($cfg['base_url'],'/').'/realms/'.$cfg['realm'].'/protocol/openid-connect'; config()->set("federated-auth.providers.$provider.issuer",$cfg['issuer']?:rtrim($cfg['base_url'],'/').'/realms/'.$cfg['realm']); config()->set("federated-auth.providers.$provider.authorization_endpoint",$cfg['authorization_endpoint']?:$base.'/auth'); config()->set("federated-auth.providers.$provider.token_endpoint",$cfg['token_endpoint']?:$base.'/token'); config()->set("federated-auth.providers.$provider.userinfo_endpoint",$cfg['userinfo_endpoint']?:$base.'/userinfo'); config()->set("federated-auth.providers.$provider.jwks_uri",$cfg['jwks_uri']?:$base.'/certs'); } } }
